import{c as t,Q as i,j as s,m as n}from"./chunks/framework.D9IbVcwA.js";const h=JSON.parse('{"title":"020-proc-scheduler-2 · 进程调度","description":"","frontmatter":{"title":"020-proc-scheduler-2 · 进程调度"},"headers":[],"relativePath":"hands-on/020-proc-scheduler-2.md","filePath":"hands-on/020-proc-scheduler-2.md","lastUpdated":1779686691000}'),c={name:"hands-on/020-proc-scheduler-2.md"};function l(o,e,r,a,d,u){return i(),s("div",null,[...e[0]||(e[0]=[n('<h1 id="_020-2-抢占式调度核心实现" tabindex="-1">020-2 抢占式调度核心实现 <a class="header-anchor" href="#_020-2-抢占式调度核心实现" aria-label="Permalink to &quot;020-2 抢占式调度核心实现&quot;">​</a></h1><h2 id="导语" tabindex="-1">导语 <a class="header-anchor" href="#导语" aria-label="Permalink to &quot;导语&quot;">​</a></h2><p>上一篇我们把 Spinlock、PerCPU 和 tss_set_rsp0 这些基础设施搭好了。现在终于到了整个 tag 020 最核心的部分——实现抢占式调度。我们要做的工作包括：让定时器中断驱动调度器的时间片管理（tick），实现真正的抢占式任务切换（schedule），创建一个什么都不干只执行 hlt 的 idle 任务，以及为未来的 Mutex/Semaphore 打好地基的 block/unblock 机制。</p><p>从协作式到抢占式的转变，本质上就是从&quot;线程主动让出 CPU&quot;变成&quot;定时器来抢走 CPU&quot;。这个转变听起来只是换了个触发源，但实际上它改变了整个调度器的调用上下文——yield() 是在普通函数调用中触发的，而 tick() 是在中断处理程序中被调用的。这个区别会在下一篇的 IF 标志修复中引发一个大坑，但这一篇我们先专注于调度逻辑本身的正确性。</p><p>这一篇涉及的新增代码量比第一篇大得多——scheduler.cpp 新增了约 100 行代码，scheduler.hpp 新增了约 15 行声明。核心新增函数有六个：tick()、schedule()、idle_entry()、block()、unblock() 和 remove_task()。同时需要修改 init()、yield()、exit_current() 和 run_first() 来适配新的抢占式逻辑。</p><h2 id="概念精讲" tabindex="-1">概念精讲 <a class="header-anchor" href="#概念精讲" aria-label="Permalink to &quot;概念精讲&quot;">​</a></h2><h3 id="时间片轮转——为什么是-2-个-tick" tabindex="-1">时间片轮转——为什么是 2 个 tick <a class="header-anchor" href="#时间片轮转——为什么是-2-个-tick" aria-label="Permalink to &quot;时间片轮转——为什么是 2 个 tick&quot;">​</a></h3><p>时间片（time slice 或 quantum）是抢占式调度中最基本的概念：每个任务被分配一段固定长的 CPU 时间，时间用完后调度器强制切换到下一个任务。OSDev Wiki 的 Scheduling Algorithms 页面推荐时间片在 20ms 到 50ms 之间——太短了上下文切换开销占比太高（每次切换要保存/恢复寄存器、刷新 TLB、可能还有 cache miss），太长了交互响应迟钝。</p><p>我们的 PIT 配置为 100Hz，每个 tick 是 10ms。时间片设为 DEFAULT_TIME_SLICE = 2，也就是 20ms 一次抢占。这个值在 QEMU 模拟环境下经过实测是合适的——如果设成 10（100ms），三个线程各自跑完自己的忙循环都用不了 100ms，抢占根本不会发生。这个教训记录在 <code>document/notes/020/001_time_slice_too_long.md</code> 中，下一篇会详细讲。</p><p>对比 Linux 的做法：Linux 的 CFS（Completely Fair Scheduler）不用固定时间片，而是给每个任务分配一个&quot;虚拟运行时间&quot;的比例，时间片根据任务数量和权重动态计算。一个 CPU 密集型任务在系统负载低时可能得到 6ms 的时间片，在负载高时可能只有 1-2ms。这种自适应方案远比固定时间片高效，但实现复杂度也高得多。Cinux 选择固定时间片是因为简单——教学内核不需要处理数千个并发任务。</p><p>时间片（time slice 或 quantum）是抢占式调度中最基本的概念：每个任务被分配一段固定长的 CPU 时间，时间用完后调度器强制切换到下一个任务。OSDev Wiki 的 Scheduling Algorithms 页面推荐时间片在 20ms 到 50ms 之间——太短了上下文切换开销占比太高（每次切换要保存/恢复寄存器、刷新 TLB、可能还有 cache miss），太长了交互响应迟钝。</p><p>我们的 PIT 配置为 100Hz，每个 tick 是 10ms。时间片设为 DEFAULT_TIME_SLICE = 2，也就是 20ms 一次抢占。这个值在 QEMU 模拟环境下经过实测是合适的——如果设成 10（100ms），三个线程各自跑完自己的忙循环都用不了 100ms，抢占根本不会发生。这个教训记录在 <code>document/notes/020/001_time_slice_too_long.md</code> 中，下一篇会详细讲。</p><h3 id="tick-与-schedule-的分工" tabindex="-1">tick() 与 schedule() 的分工 <a class="header-anchor" href="#tick-与-schedule-的分工" aria-label="Permalink to &quot;tick() 与 schedule() 的分工&quot;">​</a></h3><p>我们把&quot;是否该切换&quot;和&quot;怎么切换&quot;拆成两个函数，这是有意的分层设计。tick() 是定时器中断的回调——它负责计数和判断：当前任务已经跑了几个 tick 了？有没有超过时间片？如果超过了，它重置计数器并调用 schedule()。schedule() 是真正的切换逻辑——它不管&quot;为什么切换&quot;，只管&quot;切换到谁&quot;以及&quot;怎么切换&quot;。</p><p>这种分工让 schedule() 可以被其他场景复用——block() 在阻塞当前任务时也调用 schedule()，yield() 的实现也是直接调用 schedule()。如果你把计数逻辑和切换逻辑耦合在一起，每次调用点都得重复写判断代码，维护起来会非常痛苦。</p><p>对比 Linux 的做法：<code>scheduler_tick()</code> 只负责更新运行时统计和设置 <code>TIF_NEED_RESCHED</code> 标志，实际的上下文切换推迟到下一个 preemption point。这种延迟抢占模型更灵活，但需要维护 preempt_count 等复杂机制。Cinux 选择直接在 tick 中调用 schedule 是因为当前只有内核线程，没有用户态和抢占计数的概念。</p><h3 id="idle-任务——cpu-不能停下来" tabindex="-1">idle 任务——CPU 不能停下来 <a class="header-anchor" href="#idle-任务——cpu-不能停下来" aria-label="Permalink to &quot;idle 任务——CPU 不能停下来&quot;">​</a></h3><p>当所有真实任务都处于 Blocked 或 Dead 状态时，调度器需要一个&quot;兜底&quot;任务来执行——否则 pick_next() 返回 nullptr，调度器不知道该怎么办了。idle 任务就是这个兜底：它永远处于 Ready 状态（实际上不加入 RoundRobin 队列），永远执行 <code>hlt</code> 指令让 CPU 进入低功耗等待状态。中断到来时 CPU 自动醒来，处理完中断后回到 hlt 继续等待。</p><p>idle 任务的优先级设为 255——最低。在当前只使用 RoundRobin 的场景下优先级没有实际作用，但这是为将来实现优先级调度做的预留。idle 任务也不加入 RoundRobin 队列，而是在 schedule() 中 pick_next() 返回 nullptr 时作为备选被选中。如果连 idle 都没有（理论上不应该发生），调度器就执行 <code>cli; hlt</code> 永久停机。</p><p>为什么不用一个简单的 &quot;halt 循环&quot; 代替 idle 任务？技术上可以在 schedule() 中检测 &quot;没有可运行任务&quot; 时直接进入 <code>while(1) { hlt; }</code>，不需要创建专门的 idle 任务。但这种做法有几个问题：第一，进入 halt 循环后，调度器没有一个&quot;当前任务&quot;可以管理——g_per_cpu.current 指向谁？第二，如果需要统计 CPU 空闲时间、检测系统负载，idle 任务提供了一个挂载点——<code>if (current() == idle_task_)</code> 就能判断当前是否空闲。第三，idle 任务保持了一个统一的执行流模型——所有执行流都是 Task，不存在&quot;调度器自己也在执行&quot;的特殊情况。</p><h3 id="block-unblock——为同步原语铺路" tabindex="-1">block/unblock——为同步原语铺路 <a class="header-anchor" href="#block-unblock——为同步原语铺路" aria-label="Permalink to &quot;block/unblock——为同步原语铺路&quot;">​</a></h3><p>block 和 unblock 是比 Spinlock 更高层次的同步机制。Spinlock 是&quot;忙等&quot;——拿不到锁就原地转圈，CPU 时间全浪费了。block 的思路是&quot;拿不到锁就睡觉&quot;——把任务标记为 Blocked、从运行队列中移除，CPU 去执行别的任务。等锁可用了再 unblock——把任务重新标记为 Ready、放回运行队列。</p><p>block() 接受一个 reason 字符串参数，纯粹是用于日志调试——当你看到 <code>[SCHED] Task tid=3 &#39;consumer&#39; blocked: semaphore_wait</code> 这样的日志时，立刻就知道哪个任务因为什么原因被阻塞了。在内核调试中，这种信息是无价的——死锁排查的第一步永远是&quot;谁在等什么&quot;。</p><p>unblock() 除了恢复状态还要重新入队——而且要确保任务有调度策略。如果一个任务在创建时没有指定调度策略，unblock 会把默认的 RoundRobin 分配给它，防止任务回到运行队列后没有 sched_class 指针导致空指针崩溃。</p><h2 id="动手实现" tabindex="-1">动手实现 <a class="header-anchor" href="#动手实现" aria-label="Permalink to &quot;动手实现&quot;">​</a></h2><h3 id="step-1-实现-idle-任务" tabindex="-1">Step 1: 实现 idle 任务 <a class="header-anchor" href="#step-1-实现-idle-任务" aria-label="Permalink to &quot;Step 1: 实现 idle 任务&quot;">​</a></h3><p><strong>目标</strong>: 在 Scheduler 中创建 idle 任务及其入口函数。</p><p><strong>设计思路</strong>: idle 任务的入口函数 <code>idle_entry()</code> 极其简单——一个无限循环，循环体只有一条 <code>hlt</code> 指令。hlt 让 CPU 进入 HALT 状态，功耗降到最低，同时保持中断响应能力——当 IRQ0 定时器中断到来时 CPU 自动醒来，执行完中断处理后回到 hlt。</p><p>idle 任务在 Scheduler::init() 中创建，使用 TaskBuilder 设置入口为 idle_entry、名字为 &quot;idle&quot;、优先级为 255。创建后手动将状态设为 Ready（因为 idle 任务不通过 add_task 加入 RoundRobin 队列，所以不会在 add_task 中被设为 Ready）。</p><p><strong>实现约束</strong>: idle_entry 是一个 static 私有方法，不暴露给外部。idle_task_ 静态成员保存指针，init() 中分配，后续 schedule() 和 exit_current() 中使用。</p><p><strong>踩坑预警</strong>: idle 任务千万不要调用 add_task()——如果把它加入 RoundRobin 队列，pick_next() 就有可能选到它，即使在有其他就绪任务的情况下。idle 任务应该只在&quot;没有其他选择&quot;时才被调度。</p><p><strong>验证</strong>: 编译通过。</p><h3 id="step-2-实现-tick-——时间片计数与抢占触发" tabindex="-1">Step 2: 实现 tick()——时间片计数与抢占触发 <a class="header-anchor" href="#step-2-实现-tick-——时间片计数与抢占触发" aria-label="Permalink to &quot;Step 2: 实现 tick()——时间片计数与抢占触发&quot;">​</a></h3><p><strong>目标</strong>: 实现 Scheduler::tick()，由定时器中断在每次 IRQ0 时调用。</p><p><strong>设计思路</strong>: tick() 的逻辑非常直接。第一步检查前置条件——调度器必须已初始化（initialized_ 为 true），当前必须有正在运行的任务（current_ 不为 null）。如果不满足，直接返回。第二步递增两个计数器：tick_count_ 是全局的总 tick 计数，current_slice_ 是当前任务在本轮时间片中已经消耗的 tick 数。第三步检查时间片是否用完：如果 current_slice_ &gt;= DEFAULT_TIME_SLICE（2），重置 current_slice_ 为 0 并调用 schedule() 进行任务切换。</p><p>这里有一个微妙的设计选择：tick() 中调 schedule() 时，我们仍然处于中断上下文——IRQ0 的 ISR 正在执行。这意味着 schedule() 中的 context_switch 会从中断处理程序内部发生，被切出的任务稍后会通过 IRETQ 路径恢复执行。这个调用链下一篇会仔细分析。</p><p><strong>实现约束</strong>: tick() 是静态 public 方法。不需要任何参数——它操作的都是 Scheduler 的静态状态。先检查 initialized_ 和 current_，再做计数和判断。</p><p><strong>踩坑预警</strong>: tick() 中的 schedule() 调用是抢占式调度的核心路径。如果这里的逻辑有 bug，最常见的症状是&quot;只有第一个被抢占的任务能恢复正常，后续任务全部顺序执行&quot;——这正是 IF 标志丢失的典型表现。那个 bug 不在 tick() 本身，而在 context_switch.S 中，下一篇会详细讲。</p><p>另外要注意 <code>current_slice_</code> 的重置时机——它必须在 <code>schedule()</code> 被调用之前重置为 0（在 tick() 内部完成），而不是在 schedule() 内部重置。如果在 schedule() 内部重置，那么非 tick 触发的 schedule() 调用（比如 block() 导致的）也会重置计数器，导致下一次 tick 的时间片从 0 开始计算——这不会导致功能错误，但会让时间片计量的语义变得混乱。</p><p><strong>验证</strong>: 编译通过。运行验证需要等 PIT 集成完成后才能做。</p><h3 id="step-3-实现-schedule-——抢占式任务切换" tabindex="-1">Step 3: 实现 schedule()——抢占式任务切换 <a class="header-anchor" href="#step-3-实现-schedule-——抢占式任务切换" aria-label="Permalink to &quot;Step 3: 实现 schedule()——抢占式任务切换&quot;">​</a></h3><p><strong>目标</strong>: 实现 Scheduler::schedule()，这是抢占式调度的核心切换逻辑。</p><p><strong>设计思路</strong>: schedule() 的执行流程分为几步。第一步，保存当前任务指针到局部变量 prev。第二步，如果 prev 的状态是 Running，把它改回 Ready——因为它马上要让出 CPU 了。第三步，调用 default_rr_.pick_next() 获取下一个应该执行的任务。</p><p>如果 pick_next() 返回 nullptr 或者返回的就是 prev 自己，说明没有其他就绪任务。这时候要区分两种情况：如果 prev 不是 Blocked 也不是 Dead（它只是暂时没有别人可以替代），就继续运行 prev——把状态改回 Running，直接返回，不做 context_switch。如果 prev 是 Blocked 或 Dead（比如刚调用了 block()），就必须切换到 idle 任务了——因为 prev 已经不能继续跑了。</p><p>如果 pick_next() 返回了一个有效的不同任务 next，就开始真正的切换：更新 current_ 为 next、更新 g_per_cpu.current、重置 current_slice_ 为 0。如果 next 不是 idle 任务，调用 GDT::tss_set_rsp0(next-&gt;kernel_stack_top) 更新 TSS。最后调用 context_switch(&amp;prev-&gt;ctx, &amp;next-&gt;ctx) 完成实际的寄存器和栈切换。</p><p><strong>实现约束</strong>: schedule() 是静态 public 方法。必须使用局部变量 prev 保存旧的 current_ 值，不能直接用 current_ 作为 context_switch 的 from 参数——因为 current_ 在调用 context_switch 之前就被更新成了 next，如果用 current_-&gt;ctx 做 from，context_switch 会把新任务的寄存器保存到新任务的 CpuContext 里，变成一个昂贵的 no-op。</p><p>一个微妙但关键的正确性保证：从 <code>current_ = next</code> 到 <code>context_switch(&amp;prev-&gt;ctx, &amp;next-&gt;ctx)</code> 之间，中断仍然是关闭的（因为我们可能在中断上下文中执行）。这意味着这两个操作之间不会被另一个定时器中断打断，状态更新是原子的。如果在这里被中断打断，current_ 指向新任务但实际还没切换过去，第二次 tick() 就会在错误的状态上做调度决策——current_ 和实际运行的线程不一致。</p><p><strong>踩坑预警</strong>: 这里有一个 tag 019 就提到的经典 bug——指针覆盖。如果你写成 <code>current_ = next; context_switch(&amp;current_-&gt;ctx, &amp;next-&gt;ctx)</code>，from 和 to 就指向同一个 Task，context_switch 什么都没做，执行继续在已经让出 CPU 的任务栈上跑——这会导致各种诡异的崩溃。必须先 <code>Task* prev = current_;</code> 再 <code>current_ = next;</code>。</p><p><strong>验证</strong>: 编译通过。</p><h3 id="step-4-实现-block-和-unblock" tabindex="-1">Step 4: 实现 block() 和 unblock() <a class="header-anchor" href="#step-4-实现-block-和-unblock" aria-label="Permalink to &quot;Step 4: 实现 block() 和 unblock()&quot;">​</a></h3><p><strong>目标</strong>: 实现任务的阻塞和唤醒机制。</p><p><strong>设计思路</strong>: block() 的流程是这样的：把任务状态设为 Blocked，从其调度策略的运行队列中 dequeue 移除，打印一条日志（包含 reason 参数）。关键的一步是——如果被阻塞的是当前正在运行的任务（task == current_），必须立刻调用 schedule() 让出 CPU，因为当前任务已经不能继续跑了。如果阻塞的是别的任务（比如一个子线程被父线程阻塞），只需要标记状态并移除队列即可，不需要切换。</p><p>unblock() 是 block() 的逆操作：把任务状态设回 Ready，确保它有调度策略（没有的话分配默认的 RoundRobin），调用 enqueue 重新加入运行队列，打印日志。unblock 不需要调用 schedule()——被唤醒的任务会在下一个 tick 或者下次 schedule() 时被 pick_next() 选中。</p><p>这两个函数在 tag 020 中只是定义了接口，真正的使用者是 tag 021 的 Mutex 和 Semaphore。Mutex 的 lock() 发现锁已被持有时，会调用 block(current, &quot;waiting for mutex&quot;) 把自己挂起；当锁的持有者调用 unlock() 时，会调用 unblock(waiter) 唤醒等待队列头的线程。这种 &quot;block on contention, unblock on release&quot; 的模式是内核同步原语的标准范式。</p><p>为什么不在这里加锁？当前是单核系统，block 的调用点通常已经在中断关闭的状态下（要么从中断 handler 调用，要么在持有 Spinlock 时调用）。加锁反而会增加复杂度。Linux 的做法是在 proc 结构体上持有 p-&gt;lock，但那是因为 SMP 环境下多个 CPU 可能同时操作同一个任务。</p><p><strong>实现约束</strong>: block 和 unblock 都是静态 public 方法。block 的 reason 参数可以为 null（调用时传 nullptr），日志中会打印 &quot;unknown&quot;。unblock 中检查 sched_class 是否为 null 是防御性编程——正常情况下 add_task 已经设置了 sched_class，但万一有代码路径跳过了 add_task，这里不会崩溃。</p><p><strong>验证</strong>: 编译通过。</p><h3 id="step-5-实现-remove-task-和-is-initialized" tabindex="-1">Step 5: 实现 remove_task() 和 is_initialized() <a class="header-anchor" href="#step-5-实现-remove-task-和-is-initialized" aria-label="Permalink to &quot;Step 5: 实现 remove_task() 和 is_initialized()&quot;">​</a></h3><p><strong>目标</strong>: 补充两个辅助方法。</p><p><strong>设计思路</strong>: remove_task() 是一个显式的任务移除操作——从调度策略的队列中 dequeue，然后设置状态为 Dead。和 exit_current() 不同，remove_task 可以移除任何任务，不仅仅是当前任务。目前它主要用于测试，未来会用于进程终止（kill）的实现。</p><p>is_initialized() 就是一个 getter——返回 initialized_ 的值。PIT 的 IRQ0 handler 在调用 tick() 之前会检查这个值，防止在调度器初始化完成之前就收到定时器中断。</p><p><strong>实现约束</strong>: remove_task 检查 task 指针是否为 null，检查 sched_class 是否为 null（dequeue 前要确认调度策略存在）。is_initialized 直接返回 bool。</p><p><strong>验证</strong>: 编译通过。</p><h3 id="step-6-更新-init-和现有的-yield-exit-current-run-first" tabindex="-1">Step 6: 更新 init() 和现有的 yield()/exit_current()/run_first() <a class="header-anchor" href="#step-6-更新-init-和现有的-yield-exit-current-run-first" aria-label="Permalink to &quot;Step 6: 更新 init() 和现有的 yield()/exit_current()/run_first()&quot;">​</a></h3><p><strong>目标</strong>: 让现有的调度器方法适配新增的抢占式逻辑。</p><p><strong>设计思路</strong>: init() 中增加了 idle 任务的创建和 initialized_ 标志的设置。idle 任务在 init() 末尾创建，创建后手动设置状态为 Ready 并打印日志。initialized_ = true 放在最后——这意味着只有所有初始化步骤完成后，tick() 才会真正执行调度逻辑。</p><p>yield() 的实现简化了——它现在只需要调用 schedule()。在 tag 019 中 yield() 自己实现了 pick_next 和 context_switch 的逻辑，现在这些都统一到 schedule() 中了。</p><p>exit_current() 中增加了 idle 任务的 fallback——如果 pick_next() 返回 nullptr，不再直接 halt，而是切换到 idle 任务（如果存在的话）。同时也增加了 g_per_cpu.current 和 tss_set_rsp0 的更新。</p><p>run_first() 中增加了 g_per_cpu.current 和 tss_set_rsp0 的初始化——在第一次切换到任务之前就要设置好这两个值。</p><p>这里有一个值得强调的初始化顺序约束。run_first() 被调用时，boot_task 的 CpuContext 已经被设置好——ctx.rip 指向调用 run_first() 的那行代码之后的地址，ctx.rsp 指向 boot_task 的内核栈。run_first() 在设置好 current_ 和 g_per_cpu 后，调用 pick_next() 获取第一个真正的任务（不是 boot_task），然后通过 context_switch 从 boot_task 切换到第一个任务。boot_task 本身不会被加入 RoundRobin 队列——它只是一个临时的&quot;启动载体&quot;，用来提供初始的 context_switch 上下文。</p><p><strong>实现约束</strong>: init() 中的初始化顺序很重要——先清空所有状态（包括新增的 idle_task_、tick_count_、current_slice_），再注册调度策略，然后创建 idle 任务，最后设置 initialized_ = true。如果顺序颠倒了——比如先设置 initialized_ = true 再创建 idle 任务——那么如果在 initialized_ 和 idle 任务创建之间有一个 IRQ0 到来（虽然理论上不可能，因为我们还没 sti，但防御性编程不嫌多），tick() 会认为调度器已初始化但 idle 任务还不存在，schedule() 的回退路径会走到 <code>cli; hlt</code>。</p><p><strong>踩坑预警</strong>: yield() 简化为调用 schedule() 后，它的行为和 tag 019 不完全一样。在 tag 019 中，yield() 只切换到 RoundRobin 中的下一个任务——如果队列中只有一个任务（自己），yield() 什么都不做。在 tag 020 中，schedule() 的逻辑更复杂——如果当前任务是 Running 状态且 pick_next 返回自己，schedule() 会恢复 Running 并返回，行为和 tag 019 一样。但如果当前任务已经被标记为 Blocked（比如在 yield 之前不小心被 block 了），schedule() 会切到 idle。</p><p><strong>验证</strong>: 编译通过。</p><h3 id="step-7-编译验证" tabindex="-1">Step 7: 编译验证 <a class="header-anchor" href="#step-7-编译验证" aria-label="Permalink to &quot;Step 7: 编译验证&quot;">​</a></h3><p><strong>目标</strong>: 确认所有修改编译通过。</p><div class="language-bash vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">cmake</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> --build</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> build</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> --target</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> big_kernel</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;"> 2&gt;&amp;1</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;"> |</span><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;"> tail</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> -30</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br></div></div><p>如果编译通过，恭喜你——抢占式调度的核心逻辑已经完成了。不过如果你现在就运行，什么都不会发生——因为 PIT 的 IRQ0 handler 还没有接入 tick()，定时器中断来了也调不到调度器。这个集成工作在下一篇的第一步中完成。</p><p>新增代码的规模大致如下：scheduler.cpp 新增了约 100 行（包括 tick、schedule、block、unblock、remove_task、idle_entry 和 init/yield/exit_current/run_first 的修改），scheduler.hpp 新增了约 15 行声明，加上新增的 PerCPU 全局实例和四个静态成员定义。这是 tag 020 中代码量最大的部分。</p><h2 id="构建与运行" tabindex="-1">构建与运行 <a class="header-anchor" href="#构建与运行" aria-label="Permalink to &quot;构建与运行&quot;">​</a></h2><p>到这一步我们实现了 tick()、schedule()、block/unblock、remove_task、idle 任务和 is_initialized，并且更新了 init()、yield()、exit_current() 和 run_first()。但是内核的行为仍然和 tag 019 一样——因为 tick() 从来没有被调用过。PIT 的中断还是在空跑，每一次 IRQ0 都只是递增一下计数器然后 EOI 返回，调度器完全不知道定时器的存在。</p><p>下一篇我们会把 PIT 和 tick() 连起来，然后修复一个让笔者血压拉满的 bug——context_switch 中丢失 IF 标志的问题。修复之后你就能看到多个线程在没有任何 yield 调用的情况下被定时器中断强制交替执行了。</p><h2 id="调试技巧" tabindex="-1">调试技巧 <a class="header-anchor" href="#调试技巧" aria-label="Permalink to &quot;调试技巧&quot;">​</a></h2><p><strong>schedule() 切换后系统卡死，没有任何输出</strong>: 最可能的原因是 context_switch 的 from 和 to 指向了同一个 Task。在 schedule() 中加一个 kprintf 打印 prev 和 next 的地址和 tid，确认它们确实不同。另一种可能是 next 任务的 CpuContext 没有正确初始化——如果 ctx.rip 指向了一个无效地址，jmp *56(%rsi) 会跳到错误的位置导致 triple fault。检查 TaskBuilder 是否正确设置了 ctx.rip 为线程入口函数。</p><p><strong>idle 任务被反复调度，真实任务永远得不到 CPU</strong>: 说明真实任务没有正确地进入 RoundRobin 队列。检查 add_task() 是否被正确调用，以及 schedule() 中 prev-&gt;state 的判断是否正确——如果 prev 的状态不是 Running（比如已经是 Ready），schedule() 可能会错误地认为不需要切换。</p><p><strong>block() 后系统卡死</strong>: 如果你 block 了当前任务但没有调用 schedule()，当前任务继续以 Blocked 状态运行，下次 tick() 发现 current_-&gt;state 不是 Running 就跳过——然后 prev-&gt;state != Blocked 的判断也不会触发 idle 切换。确保 block() 中 <code>if (task == current_) schedule();</code> 这一行没有被漏掉。</p><p><strong>remove_task() 后任务仍然在运行</strong>: remove_task() 只修改了任务状态和从队列中移除，但不会触发上下文切换。如果你 remove 的是当前正在运行的任务，它还会继续执行直到下一个 tick 触发 schedule()。如果需要立刻切换，应该在 remove_task() 后手动调用 schedule()。exit_current() 就是这么做的——它先从队列中移除当前任务，再寻找下一个任务并切换。</p><p><strong>unblock() 后任务没有被立刻调度</strong>: 这是正常行为。unblock() 只是把任务重新加入 RoundRobin 队列，不做立刻调度。被唤醒的任务会在下一个 tick 或下次 schedule() 时被 pick_next() 选中。如果你需要立刻调度，可以在 unblock() 后调用 schedule()——但这通常不是必要的，因为 20ms 的时间片足够短。</p><p><strong>tick_count_ 在增长但 schedule() 从未被调用</strong>: 检查 current_slice_ 是否在 tick() 中被正确递增，以及 DEFAULT_TIME_SLICE 的值是否正确。如果 DEFAULT_TIME_SLICE 被意外设成了很大的值（比如 100），那就要等 100 个 tick（1 秒）才会触发一次调度。</p><p><strong>yield() 调用后任务立刻被切回来</strong>: 如果 RoundRobin 队列中只有一个任务（yield 的调用者自己），schedule() 中 pick_next() 返回的就是 prev 自己，schedule() 检测到 next == prev 后恢复 prev 的状态为 Running 并返回。这不是 bug，是正确行为——没有其他任务可以切换时，yield 等于空操作。如果你期望 yield 总是切到不同的任务，需要确保队列中至少有两个任务。</p><p><strong>idle 任务被反复调度，但明明有就绪任务</strong>: 最可能的原因是 add_task() 没有被正确调用——任务的 sched_class 为空，没有被加入 RoundRobin 队列。在 schedule() 中加一行 kprintf 打印 pick_next() 的返回值，如果是 nullptr 说明队列为空。然后检查 add_task() 中是否正确调用了 sched_class-&gt;enqueue(task)。</p><p><strong>编译报错 &quot;Scheduler::tick 未定义&quot;</strong>: 检查 scheduler.hpp 中是否声明了 <code>static void tick()</code>。如果声明了但链接器仍然报错，检查 scheduler.cpp 中是否有 <code>void Scheduler::tick() { ... }</code> 的定义。如果你把 tick() 的实现放在了 scheduler.hpp 中（作为 inline 函数），链接器不会报错——但这样做的风险是 scheduler.hpp 变得过于臃肿。推荐的做法是把所有实现都放在 scheduler.cpp 中。</p><p><strong>运行时日志中 idle 任务被创建了两次</strong>: 说明 Scheduler::init() 被调用了两次。检查 kernel_main 中是否有重复调用 init() 的代码路径。init() 应该只在启动时调用一次。在 init() 的开头加一个 <code>if (initialized_) return;</code> 的防御性检查可以防止这种问题。</p><h2 id="本章小结" tabindex="-1">本章小结 <a class="header-anchor" href="#本章小结" aria-label="Permalink to &quot;本章小结&quot;">​</a></h2><p>这一篇我们把抢占式调度的核心逻辑全部实现了：tick() 在每次定时器中断时递增时间片计数器并在用完时触发调度，schedule() 实现了真正的抢占式任务切换（包括 idle fallback 和 PerCPU/TSS 更新），block/unblock 提供了任务阻塞和唤醒的基础机制（为 021 的 Mutex/Semaphore 铺路），idle 任务确保了 CPU 永远有事可做。但这一切目前都是&quot;静默&quot;的——tick() 从来没被调用过。下一篇我们要做的第一件事就是把 PIT 的 IRQ0 和 tick() 连起来，然后修复 context_switch 中丢失 IF 标志的经典 bug，让抢占式调度真正运转起来。</p><p>从代码结构的角度看，这一篇最重要的设计决策是把 &quot;是否该切换&quot;（tick）和 &quot;怎么切换&quot;（schedule）拆成两个函数。这种分层让 schedule() 可以被 tick()、block()、yield() 三个不同的调用者复用，避免了重复代码。如果你把计数逻辑和切换逻辑耦合在一起，每个调用点都得写一份几乎相同的判断和切换代码——这和 tag 019 中 yield() 和 exit_current() 有大量重叠代码的问题一样。schedule() 的引入消除了这种重复。</p><p>你可以用以下命令验证编译。虽然抢占式调度还不能工作，但内核应该能正常启动：</p><div class="language-bash vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">cmake</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> --build</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> build</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> --target</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> big_kernel</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;"> 2&gt;&amp;1</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;"> |</span><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;"> tail</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> -30</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br></div></div><p>如果你在运行中看到任何异常（比如崩溃、输出乱序），说明在修改 scheduler 时引入了回归。最简单的排查方式是暂时注释掉 tick() 和 schedule() 的实现，只保留 init() 和 yield() 的修改——如果问题消失了，说明 bug 在新增的函数中。</p>',98)])])}const k=t(c,[["render",l]]);export{h as __pageData,k as default};
